function active$IncomeDeductions(f) {f.add_onResponseComplete(on$IncomeDeductions$ResponseComplete);}
function close$IncomeDeductions(f) {try {f.remove_onResponseComplete(on$IncomeDeductions$ResponseComplete)} catch (ex) {}}
function on$IncomeDeductions$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_loai');
      break;
    default:
      break;
  }
}

			&ScriptIrregular;
